const express = require('express');
const axios = require('axios');

// Set up Express.js app
const app = express();

// Set up secret key (replace with your own)
const SECRET_KEY = 'your_secret_key_here';

// Set up OAuth 2.0 client ID and redirect URI
const CLIENT_ID = 'your_client_id_here';
const REDIRECT_URI = 'http://localhost:3000/callback';

// Set up token storage in session
app.use(express.session({
    secret: SECRET_KEY,
    resave: false,
    saveUninitialized: true
}));

// Authorization endpoint
app.get('/authorize', (req, res) => {
    const authUrl = `https://your-oauth-server.com/authorize?response_type=token&client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}`;
    res.redirect(authUrl);
});

// Callback endpoint to parse access token from URL fragment
app.get('/callback', (req, res) => {
    const accessToken = req.query.access_token;
    if (!accessToken) {
        res.status(401).send('Unauthorized');
        return;
    }

    // Store access token in session for the duration of the session
    req.session.accessToken = accessToken;

    // Make API call using access token (example: get user info)
    axios.get(`https://your-oauth-server.com/api/user`, {
        headers: {
            Authorization: `Bearer ${accessToken}`
        }
    })
    .then(response => {
        console.log(response.data);
        res.redirect('/');
    })
    .catch(error => {
        console.error(error);
        res.status(500).send('Internal Server Error');
    });
});

// API call using access token (example: get user info)
app.get('/api/user', (req, res) => {
    const accessToken = req.session.accessToken;
    if (!accessToken) {
        res.status(401).send('Unauthorized');
        return;
    }

    axios.get(`https://your-oauth-server.com/api/user`, {
        headers: {
            Authorization: `Bearer ${accessToken}`
        }
    })
    .then(response => {
        console.log(response.data);
        res.send(response.data);
    })
    .catch(error => {
        console.error(error);
        res.status(500).send('Internal Server Error');
    });
});

// Start Express.js server
const port = 3000;
app.listen(port, () => {
    console.log(`Server listening on port ${port}`);
});